#include<bits/stdc++.h>
using namespace std;
int a[1000010],g[1000010];
int n,m,used[1000010];
vector<int> mp[1000010],mp1[1000010];
int in[1000010];
stack<int> s;
bool instk[1000010];
int dfn[1000010],f[1000010],low[1000010],scccnt,scc[1000010],siz[1000010],val[1000010],dfncnt;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    s.push(x);
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            val[scccnt]+=a[top];
            instk[top]=false;
        }while(top!=x);
    }
}
int main()
{
    int mod;
    scanf("%d%d%d",&n,&m,&mod);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        f[i]=siz[i];
        g[i]=1;
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                in[scc[j]]++;
                mp1[scc[i]].push_back(scc[j]);
            }
        }
    }
    for(int x=scccnt;x>=1;x--)
    {
        for(int i:mp1[x])
        {
            if(used[i]==x)
            {
                continue;
            }
            used[i]=x;
            if(f[i]<f[x]+siz[i])
            {
                f[i]=f[x]+siz[i];
                g[i]=g[x];
            }
            else if(f[i]==f[x]+siz[i])
            {
                g[i]+=g[x];
                g[i]%=mod;
            }
        }
    }
    int ans=0,tmp=0;
    for(int i=1;i<=scccnt;i++)
    {
        if(f[i]>ans)
        {
            ans=f[i];
            tmp=g[i];
        }
        else if(f[i]==ans)
        {
            tmp=(tmp+g[i])%mod;
        }
    }
    printf("%d\n%d",ans,tmp);
    return 0;
}
